import pytest

class TestFormatTimeframe:
    @pytest.fixture
    def setup(self):
        class MockClass:
            timeframes = {
                'days': '{0} days',
                'weeks': {
                    'future': '{0} weeks from now',
                    'past': '{0} weeks ago'
                },
                'months': {
                    'future': '{0} months from now',
                    'past': '{0} months ago'
                }
            }

        return MockClass()

    def test_positive_delta_future(self, setup):
        result = setup._format_timeframe('weeks', 3)
        assert result == '3 weeks from now'

    def test_negative_delta_past(self, setup):
        result = setup._format_timeframe('weeks', -2)
        assert result == '2 weeks ago'

    def test_zero_delta(self, setup):
        result = setup._format_timeframe('days', 0)
        assert result == '0 days'

    def test_different_timeframes(self, setup):
        result_days = setup._format_timeframe('days', 5)
        assert result_days == '5 days'

        result_months_future = setup._format_timeframe('months', 1)
        assert result_months_future == '1 months from now'

        result_months_past = setup._format_timeframe('months', -1)
        assert result_months_past == '1 months ago'

    def test_invalid_timeframe(self, setup):
        with pytest.raises(KeyError):
            setup._format_timeframe('invalid_timeframe', 1)

    def test_large_positive_delta(self, setup):
        result = setup._format_timeframe('weeks', 2147483647)
        assert result == '2147483647 weeks from now'

    def test_large_negative_delta(self, setup):
        result = setup._format_timeframe('weeks', -2147483648)
        assert result == '2147483648 weeks ago'

    def test_non_integer_delta(self, setup):
        with pytest.raises(TypeError):
            setup._format_timeframe('weeks', 'two')

