import pytest
from typing import List, Tuple, Union, Sequence

# Assuming the class containing describe_multi is named TimeDeltaFormatter
class TimeDeltaFormatter:
    def __init__(self, and_word=None):
        self.and_word = and_word

    def _format_timeframe(self, timeframe, delta):
        return f"{delta} {timeframe}"

    def _format_relative(self, humanized, unit, value):
        return f"{humanized} ago"  # Simplified for testing

    def describe_multi(
        self,
        timeframes: Sequence[Tuple[str, Union[int, float]]],
        only_distance: bool = False,
    ) -> str:
        parts = [
            self._format_timeframe(timeframe, int(delta))
            for timeframe, delta in timeframes
        ]
        if self.and_word:
            parts.insert(-1, self.and_word)
        humanized = " ".join(parts)

        if not only_distance:
            timeframe_value = 0
            for _, unit_value in timeframes:
                if int(unit_value) != 0:
                    timeframe_value = int(unit_value)
                    break
            humanized = self._format_relative(humanized, "seconds", timeframe_value)

        return humanized

