import pytest
from random import shuffle
from operator import itemgetter

def random_derangement(iterable):
    """Return a random derangement of elements in the iterable."""
    seq = tuple(iterable)
    if len(seq) < 2:
        if len(seq) == 0:
            return ()
        raise IndexError('No derangements to choose from')
    perm = list(range(len(seq)))
    start = tuple(perm)
    while True:
        shuffle(perm)
        if not any(map(is_, start, perm)):
            return itemgetter(*perm)(seq)

def is_(a, b):
    return a is b

# Test cases
def test_random_derangement_normal_cases():
    assert len(set(random_derangement([1, 2, 3])) & {1, 2, 3}) == 0
    assert len(set(random_derangement((1, 2, 3))) & {1, 2, 3}) == 0
    assert len(set(random_derangement("abc")) & {'a', 'b', 'c'}) == 0
    assert len(set(random_derangement([1, 1, 1])) & {1}) == 0  # All elements are the same

